    typealias SwiftType = SshError

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SshError {
        let variant: Int32 = try readInt(&buf)
        switch variant {

        

        
        case 1: return .ConnectionFailed(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 2: return .AuthFailed(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 3: return .ChannelError(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 4: return .Disconnected(
            message: try FfiConverterString.read(from: &buf)
        )
        
        case 5: return .InvalidKey(
            message: try FfiConverterString.read(from: &buf)
        )
        

        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: SshError, into buf: inout [UInt8]) {
        switch value {

        

        
        case .ConnectionFailed(_ /* message is ignored*/):
            writeInt(&buf, Int32(1))
        case .AuthFailed(_ /* message is ignored*/):
            writeInt(&buf, Int32(2))
        case .ChannelError(_ /* message is ignored*/):
            writeInt(&buf, Int32(3))
        case .Disconnected(_ /* message is ignored*/):
            writeInt(&buf, Int32(4))
        case .InvalidKey(_ /* message is ignored*/):
            writeInt(&buf, Int32(5))

        
        }
    }
}


